$\begin{align}
&\phantom{=}g'(x)
\\\\
&=\dfrac{d}{dx}(\sqrt{x}\sin(x))
\\\\
&=\dfrac{d}{dx}(\sqrt{x})\sin(x)+\sqrt{x}\dfrac{d}{dx}(\sin(x))&&\gray{\text{The product rule}}
\\\\
&=\dfrac{d}{dx}\left(x^{^{\Large\frac{1}{2}}}\right)\sin(x)+\sqrt{x}\dfrac{d}{dx}(\sin(x))&&\gray{\text{Write }\sqrt{x}\text{ as a power}}
\\\\
&=\dfrac12x^{^{\Large-\frac{1}{2}}}\cdot \sin(x)+\sqrt{x}\cdot \cos(x)&&\gray{\text{Differentiate }x^{^{\Large\frac{1}{2}}}\text{ and }\sin(x)}
\\\\
&=\dfrac{\sin(x)}{2\sqrt{x}}+\sqrt{x}\cos(x)&&\gray{\text{Simplify}}
\end{align}$

$\begin{align}
&\phantom{=}\dfrac{d}{dx}\left(\cos(x)x^2\right)
\\\\
&=\dfrac{d}{dx}\left[\cos(x)\right]x^2+\cos(x)\dfrac{d}{dx}(x^2)&&\gray{\text{The product rule}}
\\\\
&=-\sin(x)x^2+\cos(x)2x&&\gray{\text{Differentiate }\cos(x)\text{ and }x^2}
\\\\
&=2x\cos(x)-x^2\sin(x)&&\gray{\text{Simplify}}
\end{align}$

$\begin{align}
&\phantom{=}\dfrac{d}{dx}\left(x^3\sin(x)\right)
\\\\
&=\dfrac{d}{dx}\left(x^3\right)\sin(x)+x^3\dfrac{d}{dx}(\sin(x))&&\gray{\text{The product rule}}
\\\\
&=3x^2\cdot\sin(x)+x^3\cdot \cos(x)&&\gray{\text{Differentiate }x^3\text{ and }\sin(x)}
\\\\
&=x^2(3\sin(x)+x\cos(x))&&\gray{\text{Simplify}}
\end{align}$

$\begin{align}
&\phantom{=}\dfrac{dy}{dx}
\\\\
&=\dfrac{d}{dx}\left[\cos(x)x^3\right]
\\\\
&=\dfrac{d}{dx}\left[\cos(x)\right]x^3+\cos(x)\dfrac{d}{dx}[x^3]&&\gray{\text{The product rule}}
\\\\
&=-\sin(x)x^3+\cos(x)3x^2&&\gray{\text{Differentiate }\cos(x)\text{ and }x^3}
\\\\
&=3x^2\cos(x)-x^3\sin(x)&&\gray{\text{Simplify}}
\end{align}$

$\begin{align}
&\phantom{=}\dfrac{dy}{dx}
\\\\
&=\dfrac{d}{dx}\left(\dfrac1x\sin(x)\right)
\\\\
&=\dfrac{d}{dx}\left(\dfrac1x\right)\sin(x)+\dfrac1x\dfrac{d}{dx}(\sin(x))&&\gray{\text{The product rule}}
\\\\
&=\dfrac{d}{dx}\left(x^{-1}\right)\sin(x)+\dfrac1x\dfrac{d}{dx}(\sin(x))&&\gray{\text{Write } \dfrac1x\text{as a power}}
\\\\
&=-1x^{-2}\cdot \sin(x)+\dfrac1x\cdot \cos(x)&&\gray{\text{Differentiate }x^{-1}\text{ and }\sin(x)}
\\\\
&=\dfrac{\cos(x)}{x}-\dfrac{\sin(x)}{x^2}&&\gray{\text{Simplify}}
\end{align}$

$\begin{align}
